import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import LoadingSpinner from '../shared/LoadingSpinner';
import AlertMessage from '../shared/AlertMessage';
import CertificateGenerator from '../CertificateGenerator';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

const UserDashboard = ({ activeTabProp }) => {
  const { currentUser } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const queryParams = new URLSearchParams(location.search);
  const certificateId = queryParams.get('certificateId');
  const statusFilter = queryParams.get('status');

  const [certificates, setCertificates] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [statusFilterState, setStatusFilter] = useState(statusFilter);
  const [stats, setStats] = useState({
    total: 0,
    pending: 0,
    issued: 0,
    revoked: 0,
  });
  const [activeTab, setActiveTab] = useState(activeTabProp || 'dashboard');
  const [selectedCertificate, setSelectedCertificate] = useState(null);
  const [certificateLoading, setCertificateLoading] = useState(false);
  const [certificateError, setCertificateError] = useState(null);
  const [downloadLoading, setDownloadLoading] = useState(false);
  const [viewerOpen, setViewerOpen] = useState(false);
  const [viewerUrl, setViewerUrl] = useState('');

  // 当组件初始化或路由参数改变时更新标签页
  useEffect(() => {
    if (activeTabProp) {
      setActiveTab(activeTabProp);
    }
  }, [activeTabProp]);

  // 如果有status过滤参数，更新标签页为certificates
  useEffect(() => {
    if (statusFilter) {
      setActiveTab('certificates');
      setStatusFilter(statusFilter);
    }
  }, [statusFilter]);

  useEffect(() => {
    const fetchUserData = async () => {
      try {
        setLoading(true);
        setError(null);

        const token = localStorage.getItem('token');

        if (!token) {
          throw new Error('Authentication required');
        }

        console.log('Fetching certificates with token:', token.substring(0, 15) + '...');

        // 获取用户的证书
        const response = await fetch('/api/certificates/user', {
          headers: {
            Authorization: `Bearer ${token}`,
          },
          credentials: 'include',
        });

        console.log('Response status:', response.status);

        // 尝试解析响应
        let data;
        try {
          const text = await response.text();
          console.log('Raw response:', text);
          data = text ? JSON.parse(text) : {};
        } catch (parseError) {
          console.error('Error parsing response:', parseError);
          throw new Error('Error parsing server response');
        }

        console.log('Response data:', data);

        if (!response.ok) {
          throw new Error(data.message || 'Failed to fetch certificates');
        }

        // 检查数据格式是否正确
        if (!data.data || !Array.isArray(data.data)) {
          console.warn('Unexpected data format:', data);
          // 设置为空数组，而不是中断
          setCertificates([]);
          setStats({
            total: 0,
            pending: 0,
            issued: 0,
            revoked: 0,
          });
          return;
        }

        // 更新证书列表
        setCertificates(data.data);

        // 计算统计数据
        const calculatedStats = {
          total: data.data.length,
          pending: data.data.filter(cert => cert.status === 'pending').length,
          issued: data.data.filter(cert => cert.status === 'issued').length,
          revoked: data.data.filter(cert => cert.status === 'revoked').length,
        };

        setStats(calculatedStats);
      } catch (err) {
        console.error('Error fetching user data:', err);
        setError(err.message || 'Server error');
      } finally {
        setLoading(false);
      }
    };

    fetchUserData();
  }, []);

  useEffect(() => {
    if (certificateId) {
      fetchCertificateDetails(certificateId);
      setActiveTab('certificate-details');
    }
  }, [certificateId]);

  const fetchCertificateDetails = async (id) => {
    try {
      setCertificateLoading(true);
      setCertificateError(null);

      const token = localStorage.getItem('token');

      if (!token) {
        throw new Error('Authentication required');
      }

      console.log(`开始获取证书ID: ${id}的详情`);
      const response = await fetch(`/api/certificates/${id}`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      console.log(`接收到状态码: ${response.status}`);

      // 尝试解析响应文本并记录日志
      const responseText = await response.text();
      console.log('接收到原始响应:', responseText);

      if (!response.ok) {
        throw new Error(`获取证书失败: ${responseText}`);
      }

      // 解析JSON数据
      const data = responseText ? JSON.parse(responseText) : {};
      console.log('解析后的证书数据:', data);

      setSelectedCertificate(data.data);
    } catch (err) {
      console.error('Error fetching certificate details:', err);
      setCertificateError(err.message || 'Failed to load certificate');
    } finally {
      setCertificateLoading(false);
    }
  };

  const handleDownloadCertificate = async (id) => {
    try {
      setDownloadLoading(true);
      const token = localStorage.getItem('token');

      if (!token) {
        throw new Error('需要身份验证');
      }

      console.log(`开始下载证书ID: ${id}`);

      // 使用API端点而不是直接构建URL，并添加token作为查询参数
      const downloadUrl = `/api/certificates/${id}/download?token=${encodeURIComponent(token)}`;

      console.log(`使用下载API: ${downloadUrl}`);

      // 使用iframe方式下载，避免DOM移除错误
      const iframe = document.createElement('iframe');
      iframe.style.display = 'none';
      iframe.src = downloadUrl;

      // 设置下载完成或错误后清除iframe
      iframe.onload = () => {
        console.log('iframe加载完成');
        // 延迟移除iframe，避免过早移除导致下载中断
        setTimeout(() => {
          try {
            if (document.body.contains(iframe)) {
              document.body.removeChild(iframe);
            }
          } catch (e) {
            console.error('移除iframe时出错:', e);
          }
        }, 1000);
      };

      // 处理可能的错误
      iframe.onerror = () => {
        console.error('iframe加载失败');
        if (document.body.contains(iframe)) {
          document.body.removeChild(iframe);
        }
        alert('下载证书失败，请重试');
      };

      // 添加到文档
      document.body.appendChild(iframe);

      console.log('下载请求已通过iframe发送');

      // 设置超时，确保iframe最终会被移除
      setTimeout(() => {
        try {
          if (document.body.contains(iframe)) {
            document.body.removeChild(iframe);
          }
        } catch (e) {
          console.error('移除iframe超时处理时出错:', e);
        }
      }, 10000);

    } catch (err) {
      console.error('证书下载错误:', err);
      alert(`下载证书失败: ${err.message}`);
    } finally {
      setTimeout(() => {
        setDownloadLoading(false);
      }, 2000);
    }
  };

  // 添加在线查看证书的函数
  const handleViewCertificate = async (id) => {
    try {
      setViewerOpen(true);
      // Construct the URL for the dedicated certificate viewer page
      const certUrl = `/certificate-embed/${id}/simple-modern`; // Using simple-modern as an example template name
      setViewerUrl(certUrl);

      // No need to use window.history.pushState here as the iframe will handle its own navigation to certUrl
    } catch (error) {
      console.error('查看证书时出错:', error);
      alert('无法查看证书，请稍后再试');
    }
  };

  // 关闭证书查看器
  const closeViewer = () => {
    setViewerOpen(false);
    setViewerUrl('');
  };

  const formatDate = dateString => {
    const options = { year: 'numeric', month: 'long', day: 'numeric' };
    return new Date(dateString).toLocaleDateString(undefined, options);
  };

  const getStatusBadgeClass = status => {
    switch (status) {
      case 'pending':
        return 'bg-yellow-100 text-yellow-800';
      case 'issued':
        return 'bg-green-100 text-green-800';
      case 'revoked':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  // 新增：所见即所得PDF下载函数
  const handleDownloadCertificatePDF = async () => {
    if (!selectedCertificate) return;
    // 找到证书详情的容器
    const certDom = document.getElementById('certificate-html-preview');
    if (!certDom) {
      alert('证书内容未渲染，无法导出PDF');
      return;
    }
    try {
      const canvas = await html2canvas(certDom, {
        scale: 3,
        useCORS: true,
        backgroundColor: '#FFFDF0',
      });
      const imgData = canvas.toDataURL('image/png', 1.0);
      const pdf = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'a4', compress: false });
      const imgWidth = 297;
      const imgHeight = 210;
      pdf.addImage(imgData, 'PNG', 0, 0, imgWidth, imgHeight, '', 'FAST');
      pdf.save(`${selectedCertificate.recipientName || selectedCertificate.name || 'certificate'}_${selectedCertificate.certificateNumber || selectedCertificate.certificateId}.pdf`);
    } catch (error) {
      console.error('下载证书失败:', error);
      alert('生成PDF时出错，请稍后再试');
    }
  };

  // 新增：根据selectedCertificate生成SVG字符串
  function getCertificateSVG(cert) {
    if (!cert) return '';
    const origin = window.location.origin;
    let svg = `<?xml version="1.0" encoding="UTF-8"?>
<svg width="1200" height="900" xmlns="http://www.w3.org/2000/svg">
  <rect width="1200" height="900" fill="#FFFDF0" />
  <rect x="50" y="50" width="1100" height="800" fill="none" stroke="#B58A3F" stroke-width="3" />
  <image x="550" y="100" width="100" height="100" href="${origin}/images/logo/logo.svg" />
  <text x="600" y="250" font-family="Georgia, serif" font-size="40" font-weight="bold" text-anchor="middle" fill="#000000">STRATFORD INTERNATIONAL UNIVERSITY</text>
  <text x="600" y="320" font-family="Georgia, serif" font-size="60" font-weight="bold" text-anchor="middle" fill="#B58A3F">DIPLOMA</text>
  <text x="600" y="380" font-family="Georgia, serif" font-size="22" text-anchor="middle" fill="#000000">This is to certify that</text>
  <text x="600" y="450" font-family="Georgia, serif" font-size="40" font-weight="bold" text-anchor="middle" fill="#000000">${cert.recipientName || cert.name || ''}</text>
  <text x="600" y="510" font-family="Georgia, serif" font-size="22" text-anchor="middle" fill="#000000">has successfully completed the online degree</text>
  <text x="600" y="580" font-family="Georgia, serif" font-size="36" font-style="italic" font-weight="bold" text-anchor="middle" fill="#B58A3F">${cert.program || cert.course || ''}</text>
  <text x="600" y="640" font-family="Georgia, serif" font-size="18" text-anchor="middle" fill="#000000">together with all the rights, privileges and honours which appertain thereto.</text>
  <text x="600" y="680" font-family="Georgia, serif" font-size="18" text-anchor="middle" fill="#000000">Awarded Date</text>
  <text x="600" y="710" font-family="Georgia, serif" font-size="22" text-anchor="middle" fill="#000000">${formatDate(cert.issueDate || cert.date)}</text>
  <line x1="300" y1="780" x2="450" y2="780" stroke="#000000" stroke-width="1" />
  <line x1="750" y1="780" x2="900" y2="780" stroke="#000000" stroke-width="1" />

  <!-- 左侧签名图片 -->
  <image x="320" y="750" width="120" height="40" href="${origin}/images/signatures/president.png" />
  <!-- 右侧签名图片 -->
  <image x="760" y="750" width="120" height="40" href="${origin}/images/signatures/director.png" />
  <!-- 中间校徽 -->
  <image x="570" y="750" width="60" height="60" href="${origin}/images/logo/logo.png" />

  <text x="375" y="825" font-family="Georgia, serif" font-size="14" text-anchor="middle" fill="#000000">University President</text>
  <text x="825" y="825" font-family="Georgia, serif" font-size="14" text-anchor="middle" fill="#000000">Program Director</text>
  <text x="600" y="870" font-family="Georgia, serif" font-size="14" text-anchor="middle" fill="#000000">Certificate ID: ${cert.certificateNumber || cert.certificateId || ''}</text>
</svg>`;
    return svg;
  }

  return (
    <>
      <div className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
        {/* 页面标题 */}
        <div className="md:flex md:items-center md:justify-between mb-4 px-4 sm:px-0">
          <div className="flex-1 min-w-0">
            <h2 className="text-2xl font-bold leading-7 text-gray-900 sm:text-3xl sm:truncate">
              Dashboard
            </h2>
          </div>
        </div>

        {/* 欢迎信息 */}
        <div className="px-4 sm:px-0">
          <h3 className="text-lg font-medium leading-6 text-gray-900">
            Welcome back, {currentUser?.name || currentUser?.email?.split('@')[0] || 'User'}!
          </h3>
          <p className="mt-1 text-sm text-gray-600">
            Here&apos;s an overview of your certificates and recent activity.
          </p>
        </div>

        {/* Tab navigation */}
        <div className="border-b border-gray-200 mt-6">
          <nav className="-mb-px flex space-x-8 px-4 sm:px-0">
            <button
              className={`${
                activeTab === 'dashboard'
                  ? 'border-blue-500 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
              } whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm`}
              onClick={() => setActiveTab('dashboard')}
            >
              Dashboard
            </button>
            <button
              className={`${
                activeTab === 'generate-certificate'
                  ? 'border-blue-500 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
              } whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm`}
              onClick={() => setActiveTab('generate-certificate')}
            >
              Generate SIU Certificate
            </button>
            {activeTab === 'certificate-details' && (
              <button
                className="border-blue-500 text-blue-600 whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm"
              >
                Certificate Details
              </button>
            )}
          </nav>
        </div>

        {loading && activeTab === 'dashboard' ? (
          <LoadingSpinner message="Loading your dashboard..." />
        ) : error && activeTab === 'dashboard' ? (
          <AlertMessage
            type="error"
            message={{
              title: 'Failed to load dashboard',
              details: error,
            }}
          />
        ) : (
          <>
            {activeTab === 'dashboard' && (
              <>
                {/* 统计卡片 */}
                <div className="mt-6 grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-4 px-4 sm:px-0">
                  {/* 总证书数量 */}
                  <div className="bg-white overflow-hidden shadow rounded-lg">
                    <div className="px-4 py-5 sm:p-6">
                      <div className="flex items-center">
                        <div className="flex-shrink-0 bg-blue-500 rounded-md p-3">
                          <svg
                            className="h-6 w-6 text-white"
                            xmlns="http://www.w3.org/2000/svg"
                            fill="none"
                            viewBox="0 0 24 24"
                            stroke="currentColor"
                          >
                            <path
                              strokeLinecap="round"
                              strokeLinejoin="round"
                              strokeWidth={2}
                              d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"
                            />
                          </svg>
                        </div>
                        <div className="ml-5 w-0 flex-1">
                          <dl>
                            <dt className="text-sm font-medium text-gray-500 truncate">
                              Total Certificates
                            </dt>
                            <dd>
                              <div className="text-lg font-medium text-gray-900">{stats.total}</div>
                            </dd>
                          </dl>
                        </div>
                      </div>
                    </div>
                    <div className="bg-gray-50 px-4 py-4 sm:px-6">
                      <div className="text-sm">
                        <Link
                          to="/user-certificates"
                          className="font-medium text-blue-600 hover:text-blue-500"
                        >
                          View all<span className="sr-only"> certificates</span>
                        </Link>
                      </div>
                    </div>
                  </div>

                  {/* 待审核证书 */}
                  <div className="bg-white overflow-hidden shadow rounded-lg">
                    <div className="px-4 py-5 sm:p-6">
                      <div className="flex items-center">
                        <div className="flex-shrink-0 bg-yellow-500 rounded-md p-3">
                          <svg
                            className="h-6 w-6 text-white"
                            xmlns="http://www.w3.org/2000/svg"
                            fill="none"
                            viewBox="0 0 24 24"
                            stroke="currentColor"
                          >
                            <path
                              strokeLinecap="round"
                              strokeLinejoin="round"
                              strokeWidth={2}
                              d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"
                            />
                          </svg>
                        </div>
                        <div className="ml-5 w-0 flex-1">
                          <dl>
                            <dt className="text-sm font-medium text-gray-500 truncate">
                              Pending Approval
                            </dt>
                            <dd>
                              <div className="text-lg font-medium text-gray-900">
                                {stats.pending}
                              </div>
                            </dd>
                          </dl>
                        </div>
                      </div>
                    </div>
                    <div className="bg-gray-50 px-4 py-4 sm:px-6">
                      <div className="text-sm">
                        <Link
                          to="/user-certificates?status=pending"
